const budgetRows = $('Get Current Week Budget').all();
const budget = budgetRows.length ? budgetRows[0].json : null;
const byCategory = $('Get Week-to-Date By Category').all().map(i => i.json);
const totals = $('Get Weekday-Weekend Totals').first().json;

if (!budget) {
  return [{ json: { message: 'No budget row found for this week yet — run "Weekly Budget Calc" to generate one.' } }];
}

const weekdayRemaining = Number(budget.weekly_budget) - Number(totals.weekday_spent);
const weekendRemaining = Number(budget.weekend_budget) - Number(totals.weekend_spent);

const lines = [`Morning summary — week ${budget.week_number}`, ''];
lines.push(`Weekday pool: R${totals.weekday_spent} spent of R${budget.weekly_budget} (R${weekdayRemaining.toFixed(2)} left)`);
lines.push(`Weekend pool: R${totals.weekend_spent} spent of R${budget.weekend_budget} (R${weekendRemaining.toFixed(2)} left)`);
lines.push('');
lines.push('By category this week:');
if (byCategory.length === 0) {
  lines.push('  (nothing logged yet)');
} else {
  for (const row of byCategory) {
    lines.push(`  ${row.name}: R${row.spent}`);
  }
}

return [{ json: { message: lines.join('\n') } }];
